defmodule SessionPlug do
  import Plug.Conn

  @cookie_name "app_session"
  @cookie_opts [
    http_only: true,
    secure: true,
    same_site: "Lax",
    max_age: 3600
  ]

  def init(opts), do: opts

  def call(conn, _opts) do
    session_data = get_session_cookie(conn)
    
    case SessionManager.deserialize_session(session_data) do
      {:ok, session} ->
        refreshed_session_data = SessionManager.refresh_session(session)
        
        conn
        |> put_session_cookie(refreshed_session_data)
        |> assign(:current_session, session)
        |> assign(:current_user_id, SessionManager.get_user_id(session))
        
      {:error, _reason} ->
        conn
        |> assign(:current_session, nil)
        |> assign(:current_user_id, nil)
    end
  end

  defp get_session_cookie(conn) do
    case get_req_header(conn, "cookie") do
      [] -> nil
      cookies ->
        cookies
        |> Enum.join("; ")
        |> parse_cookies()
        |> Map.get(@cookie_name)
    end
  end

  defp parse_cookies(cookie_string) do
    cookie_string
    |> String.split("; ")
    |> Enum.map(fn cookie ->
      case String.split(cookie, "=", parts: 2) do
        [key, value] -> {key, value}
        _ -> nil
      end
    end)
    |> Enum.reject(&is_nil/1)
    |> Map.new()
  end

  defp put_session_cookie(conn, session_data) do
    put_resp_cookie(conn, @cookie_name, session_data, @cookie_opts)
  end
end

defmodule SessionController do
  import Plug.Conn

  @cookie_name "app_session"
  @cookie_opts [
    http_only: true,
    secure: true,
    same_site: "Lax",
    max_age: 3600
  ]

  def create(conn, %{"user_id" => user_id} = params) do
    session_data = Map.get(params, "data", %{})
    serialized_session = SessionManager.create_session(user_id, session_data)
    
    conn
    |> put_resp_cookie(@cookie_name, serialized_session, @cookie_opts)
    |> put_resp_content_type("application/json")
    |> send_resp(200, Jason.encode!(%{status: "success", message: "Session created"}))
  end

  def update(conn, %{"data" => data}) do
    case conn.assigns[:current_session] do
      nil ->
        conn
        |> put_resp_content_type("application/json")
        |> send_resp(401, Jason.encode!(%{error: "No active session"}))
        
      session ->
        updated_session = SessionManager.update_session(session, data)
        
        conn
        |> put_resp_cookie(@cookie_name, updated_session, @cookie_opts)
        |> put_resp_content_type("application/json")
        |> send_resp(200, Jason.encode!(%{status: "success", message: "Session updated"}))
    end
  end

  def show(conn, _params) do
    case conn.assigns[:current_session] do
      nil ->
        conn
        |> put_resp_content_type("application/json")
        |> send_resp(401, Jason.encode!(%{error: "No active session"}))
        
      session ->
        session_info = %{
          user_id: SessionManager.get_user_id(session),
          data: SessionManager.get_session_data(session),
          created_at: session.created_at,
          expires_at: session.expires_at
        }
        
        conn
        |> put_resp_content_type("application/json")
        |> send_resp(200, Jason.encode!(session_info))
    end
  end

  def destroy(conn, _params) do
    conn
    |> delete_resp_cookie(@cookie_name)
    |> put_resp_content_type("application/json")
    |> send_resp(200, Jason.encode!(%{status: "success", message: "Session destroyed"}))
  end
end

defmodule DistributedSessionStore do
  use GenServer

  def start_link(opts \\ []) do
    GenServer.start_link(__MODULE__, opts, name: __MODULE__)
  end

  def init(_opts) do
    :ets.new(:session_store, [:named_table, :public, read_concurrency: true])
    {:ok, %{}}
  end

  def store_session(session_id, session_data) do
    serialized = :erlang.term_to_binary(session_data)
    :ets.insert(:session_store, {session_id, serialized, :os.system_time(:second)})
    :ok
  end

  def get_session(session_id) do
    case :ets.lookup(:session_store, session_id) do
      [{^session_id, serialized, _timestamp}] ->
        {:ok, :erlang.binary_to_term(serialized, [:safe])}
      [] ->
        {:error, :not_found}
    end
  end

  def delete_session(session_id) do
    :ets.delete(:session_store, session_id)
    :ok
  end

  def cleanup_expired(max_age) do
    now = :os.system_time(:second)
    cutoff = now - max_age
    
    :ets.select_delete(:session_store, [
      {{:_, :_, :"$1"}, [{:<, :"$1", cutoff}], [true]}
    ])
  end
end

defmodule SessionCleanupWorker do
  use GenServer

  @cleanup_interval 300_000

  def start_link(opts \\ []) do
    GenServer.start_link(__MODULE__, opts, name: __MODULE__)
  end

  def init(_opts) do
    schedule_cleanup()
    {:ok, %{}}
  end

  def handle_info(:cleanup, state) do
    DistributedSessionStore.cleanup_expired(3600)
    schedule_cleanup()
    {:noreply, state}
  end

  defp schedule_cleanup do
    Process.send_after(self(), :cleanup, @cleanup_interval)
  end
end